import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"巴菲特致股东信核心总结 · 1999年","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1999年/核心总结.md","filePath":"01_letters/1999年/核心总结.md"}'),r={name:"01_letters/1999年/核心总结.md"};function h(o,a,d,n,u,s){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="巴菲特致股东信核心总结-·-1999年" tabindex="-1">巴菲特致股东信核心总结 · 1999年 <a class="header-anchor" href="#巴菲特致股东信核心总结-·-1999年" aria-label="Permalink to &quot;巴菲特致股东信核心总结 · 1999年&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净值增长3.58亿美元，每股账面价值仅增长0.5%</li><li>过去35年每股账面价值年复合增长率24.0%</li><li>这是巴菲特任职期间最差的绝对表现和相对表现</li></ul><h2 id="核心教训" tabindex="-1">核心教训 <a class="header-anchor" href="#核心教训" aria-label="Permalink to &quot;核心教训&quot;">​</a></h2><ul><li>资本配置成绩为D</li><li>几家最大投资对象的经营业绩令人失望</li><li>股票表现落后于标普500指数</li></ul><h2 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h2><h3 id="乔丹家具公司" tabindex="-1">乔丹家具公司 <a class="header-anchor" href="#乔丹家具公司" aria-label="Permalink to &quot;乔丹家具公司&quot;">​</a></h3><ul><li>新英格兰地区领先的家具零售商</li><li>每平方英尺销售额全国最高</li><li>塔特尔曼兄弟向每位员工支付每小时50美分的补偿金（总计900万美元）</li></ul><h3 id="中美能源公司" tabindex="-1">中美能源公司 <a class="header-anchor" href="#中美能源公司" aria-label="Permalink to &quot;中美能源公司&quot;">​</a></h3><ul><li>投资约20亿美元获得76%股权权益</li><li>因监管限制仅获得略低于10%表决权</li><li>沃尔特·斯科特担任控股股东</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金与成本" tabindex="-1">浮存金与成本 <a class="header-anchor" href="#浮存金与成本" aria-label="Permalink to &quot;浮存金与成本&quot;">​</a></h3><ul><li>1999年浮存金成本为5.8%</li><li>承保亏损14亿美元</li><li>阿吉特·贾恩的再保险业务贡献63亿美元浮存金</li></ul><h3 id="通用再保险" tabindex="-1">通用再保险 <a class="header-anchor" href="#通用再保险" aria-label="Permalink to &quot;通用再保险&quot;">​</a></h3><ul><li>出现巨额承保亏损（尽管投资收入使公司保持盈利）</li><li>定价严重不足问题正在改善</li></ul><h2 id="盖可保险-geico" tabindex="-1">盖可保险（GEICO） <a class="header-anchor" href="#盖可保险-geico" aria-label="Permalink to &quot;盖可保险（GEICO）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>新汽车保单</th><th>有效保单数</th></tr></thead><tbody><tr><td>1995</td><td>443,539</td><td>2,310,037</td></tr><tr><td>1999</td><td>1,648,095</td><td>4,328,900</td></tr></tbody></table><ul><li>营销支出从1995年3,300万美元增至1999年2.42亿美元</li><li>个人汽车保险市场份额从2.7%增至4.1%</li><li>利润分享支付1.133亿美元（占工资28.4%）</li></ul><h2 id="投资组合" tabindex="-1">投资组合 <a class="header-anchor" href="#投资组合" aria-label="Permalink to &quot;投资组合&quot;">​</a></h2><p>主要持仓：</p><ul><li>可口可乐：116.5亿美元</li><li>美国运通：84.02亿美元</li><li>吉列：39.54亿美元</li><li>富国银行：23.91亿美元</li></ul><h2 id="核心投资理念" tabindex="-1">核心投资理念 <a class="header-anchor" href="#核心投资理念" aria-label="Permalink to &quot;核心投资理念&quot;">​</a></h2><h3 id="能力圈" tabindex="-1">能力圈 <a class="header-anchor" href="#能力圈" aria-label="Permalink to &quot;能力圈&quot;">​</a></h3><ul><li>承认在科技领域缺乏洞察力</li><li>不持有科技股，但认同科技改变社会</li><li>专注于理解的企业</li></ul><h3 id="市场预期批评" tabindex="-1">市场预期批评 <a class="header-anchor" href="#市场预期批评" aria-label="Permalink to &quot;市场预期批评&quot;">​</a></h3><ul><li>投资者预期回报过于乐观</li><li>企业利润增长与GDP挂钩（约5%）</li><li>股票长期回报将远低于过去</li></ul><h2 id="收购会计争议" tabindex="-1">收购会计争议 <a class="header-anchor" href="#收购会计争议" aria-label="Permalink to &quot;收购会计争议&quot;">​</a></h2><h3 id="权益结合法-vs-购买法" tabindex="-1">权益结合法 vs 购买法 <a class="header-anchor" href="#权益结合法-vs-购买法" aria-label="Permalink to &quot;权益结合法 vs 购买法&quot;">​</a></h3><ul><li>管理层偏爱权益结合法以避免商誉摊销</li><li>巴菲特提出替代方案：记录公允价值但不要求摊销</li><li>如果经济商誉减值则进行减记</li></ul><h2 id="管理故事-r-c-willey" tabindex="-1">管理故事：R.C. Willey <a class="header-anchor" href="#管理故事-r-c-willey" aria-label="Permalink to &quot;管理故事：R.C. Willey&quot;">​</a></h2><ul><li>犹他州占主导地位的家装企业，坚持周日不营业</li><li>比尔·柴尔德个人投资900万美元开设博伊西门店</li><li>如果失败由他承担损失，成功后以成本价卖给伯克希尔</li><li>门店立即取得巨大成功</li></ul><h2 id="公司治理" tabindex="-1">公司治理 <a class="header-anchor" href="#公司治理" aria-label="Permalink to &quot;公司治理&quot;">​</a></h2><ul><li>伯克希尔管理者75%已独立致富</li><li>没有合同约束，因为热爱自己的企业而工作</li><li>38年来无重要子公司经理自愿离开</li></ul><h2 id="其他要点" tabindex="-1">其他要点 <a class="header-anchor" href="#其他要点" aria-label="Permalink to &quot;其他要点&quot;">​</a></h2><ul><li>年度会议移至市民礼堂</li><li>员工总数约11万人，总部员工仍为12.8人</li><li>股东指定捐赠累计1.47亿美元</li></ul><hr><p><em>核心要点总结完成</em></p>',37)])])}const q=l(r,[["render",h]]);export{b as __pageData,q as default};
